  const parts: string[] = [];

  for (const message of messages) {
    if (message.role !== "assistant") {
      continue;
    }

    const text = message.content
      .filter(
        (c): c is { type: "text"; text: string } =>
          c.type === "text" && !!c.text,
      )
      .map((c) => c.text)
      .join("\n")
      .trim();

