    ...Object.entries(COMMIT_TYPES).map(
      ([type, desc]) => `  ${type.padEnd(9)}— ${desc}`,
    ),
    "",
    "Output format — repeat for each group:",
    "",
    "=== COMMIT N ===",
    "type(scope): description",
    "",
    "Body paragraph(s).",
    "=== FILES ===",
    "relative/path/to/file1.ts",
    "relative/path/to/file2.ts",
    "=== END ===",
